+//////////////////////////////////////////////////////////////////////////////////////////////
+template <typename PointT> bool
+transformPointCloud (const std::string &target_frame,
+                     const ros::Time & target_time,
+                     const pcl::PointCloud <PointT> &cloud_in,
+                     const std::string &fixed_frame,
